const SOURCE_CONFIG = {
  "bdo-dollar-money-market-fund": {
    "bank_id": 6,
    "source_name": "BDO DOLLAR MONEY MARKET FUND"
  },
  "chinabank-dollar-cash-fund": {
    "bank_id": 7,
    "source_name": "CHINABANK DOLLAR CASH FUND"
  },
  "landbank-us-dollar-money-market-fund": {
    "bank_id": 9,
    "source_name": "LANDBANK US$ Money Market Fund"
  },
  "metro-dollar-money-market-fund": {
    "bank_id": 1,
    "source_name": "Metro$ Money Market Fund"
  },
  "pnb-prime-dollar-money-market-fund": {
    "bank_id": 2,
    "source_name": "PNB PRIME DOLLAR MONEY MARKET FUND"
  }
};
function nodeRows(name) {
  return $items(name).flatMap((item) => {
    if (Array.isArray(item.json)) return item.json;
    if (Array.isArray(item.json.data)) return item.json.data;
    return Object.keys(item.json || {}).length ? [item.json] : [];
  });
}
function decode(value) {
  return String(value || '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;|&#038;/g, '&')
    .replace(/&#8211;|&ndash;/g, '-')
    .replace(/&#x27;|&#39;/g, String.fromCharCode(39))
    .replace(/&quot;|&#34;/g, String.fromCharCode(34));
}
function strip(value) {
  return decode(value)
    .replace(/<!--[\s\S]*?-->/g, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}
function norm(value) {
  return String(value || '').toLowerCase().replace(/&/g, 'and').split('$').join(' dollar ').replace(/[^a-z0-9]+/g, ' ').trim();
}
function parseNumber(value) {
  const parsed = Number(String(value || '').replace(/,/g, '').trim());
  return Number.isFinite(parsed) ? parsed : null;
}
function parseSourceDate(text) {
  const match = text.match(/NAVpus\) as of ([A-Za-z]+)\s+(\d{1,2}),\s*(\d{4})/i);
  if (!match) throw new Error('Could not find UITF source date. Sample: ' + text.slice(0, 400));
  const months = { jan: '01', feb: '02', mar: '03', apr: '04', may: '05', jun: '06', jul: '07', aug: '08', sep: '09', oct: '10', nov: '11', dec: '12' };
  const month = months[match[1].slice(0, 3).toLowerCase()];
  if (!month) throw new Error('Unparseable UITF source month: ' + match[1]);
  return match[3] + '-' + month + '-' + String(match[2]).padStart(2, '0');
}
function parseRows(html, bankId) {
  const text = strip(html);
  const sourceDate = parseSourceDate(text);
  return [...html.matchAll(/<tr[\s\S]*?<\/tr>/gi)].map((match) => match[0].replace(/<!--[\s\S]*?-->/g, ' ')).map((row) => {
    const cells = [...row.matchAll(/<td[^>]*>([\s\S]*?)<\/td>/gi)].map((match) => strip(match[1])).filter(Boolean);
    if (cells.length < 4) return null;
    const numeric = cells.slice(1).map(parseNumber).filter((value) => value !== null);
    if (numeric.length < 3) return null;
    return { bank_id: bankId, source_date: sourceDate, name: cells[0], navpu: numeric[0], roi_yoy: numeric[1] };
  }).filter(Boolean);
}
function roundRate(value) {
  return Number(value.toFixed(6));
}
const funds = nodeRows('Get Target Funds').filter((row) => row.id);
if (!funds.length) throw new Error('No target UITF funds returned from Supabase');
const benchmarks = nodeRows('Get Latest Benchmark').filter((row) => row.rate !== undefined && row.rate !== null);
if (!benchmarks.length) throw new Error('Missing US_TBILL_90D benchmark. Run the benchmark workflow first.');
const benchmarkRate = Number(benchmarks[0].rate);
const benchmarkComparableRate = benchmarkRate * 1;
const requestItems = $items('Build Source Requests');
const sourceItems = $items('Fetch UITF Provider Sources');
const rows = [];
sourceItems.forEach((item, index) => {
  const request = requestItems[index]?.json || {};
  const raw = item.json.data || item.json.body || item.json.html || item.json.response || '';
  const html = typeof raw === 'string' ? raw : JSON.stringify(raw || {});
  if (!html || html === '{}') throw new Error('UITF provider source returned no usable body for bank_id=' + request.bank_id);
  if (/incapsula|request unsuccessful|incident id/i.test(html)) throw new Error('UITF source blocked request for bank_id=' + request.bank_id + ': ' + strip(html).slice(0, 300));
  rows.push(...parseRows(html, Number(request.bank_id)));
});
const rowsByBankAndName = new Map(rows.map((row) => [row.bank_id + ':' + norm(row.name), row]));
const output = [];
const missing = [];
for (const fund of funds) {
  const config = SOURCE_CONFIG[fund.slug];
  if (!config) {
    missing.push(fund.slug + ' has no source config');
    continue;
  }
  const row = rowsByBankAndName.get(config.bank_id + ':' + norm(config.source_name));
  if (!row) {
    missing.push(fund.provider + ' - ' + fund.name + ' expected source row ' + config.source_name);
    continue;
  }
  const grossYield = Number(row.roi_yoy) / 100;
  const afterTaxYield = grossYield * 0.8;
  const netYield = afterTaxYield - Number(fund.trust_fee_pct || 0);
  output.push({ json: { fund_id: fund.id, date: row.source_date, navpu: row.navpu, gross_yield_1y: roundRate(grossYield), after_tax_yield: roundRate(afterTaxYield), net_yield: roundRate(netYield), benchmark_rate: roundRate(benchmarkRate), vs_benchmark: roundRate(netYield - benchmarkComparableRate), data_source: 'scraper' } });
}
if (missing.length) {
  const seen = rows.slice(0, 40).map((row) => row.bank_id + ':' + row.name + ' (' + row.roi_yoy + '%)').join('; ');
  throw new Error('Missing UITF source rows: ' + missing.join('; ') + '. Parsed sample: ' + seen);
}
return output;

